const EXTRA_GRAMMAR = [
  {lv:'HSK 1',t:'The 是...的 Structure',cn:'是...的',py:'shì...de',f:'Emphasize time, place, or manner of a past action.',en:'I came yesterday.',b:'<p>Use <b>是...的</b> to emphasize details about a past action (when, where, how).</p><p class="mt-2"><b>Structure:</b> Subject + 是 + detail + verb + 的</p><p class="mt-3"><span class="fc font-bold text-lg">我是昨天来的。</span><br><span style="color:var(--muted)">Wǒ shì zuótiān lái de.</span><br>I came <b>yesterday</b>.</p><p class="mt-2"><span class="fc font-bold text-lg">他是坐飞机来的。</span><br><span style="color:var(--muted)">Tā shì zuò fēijī lái de.</span><br>He came <b>by plane</b>.</p>'},
  {lv:'HSK 1',t:'The 了 Completion Particle',cn:'了',py:'le',f:'Indicates a completed action or a change of state.',en:'I ate.',b:'<p>了 has two main uses:</p><p><b>1) Completed action:</b> Verb + 了</p><p class="mt-1"><span class="fc font-bold text-lg">我吃了。</span><br><span style="color:var(--muted)">Wǒ chī le.</span><br>I ate.</p><p class="mt-2"><b>2) Change of state:</b> Sentence + 了</p><p class="mt-1"><span class="fc font-bold text-lg">天冷了。</span><br><span style="color:var(--muted)">Tiān lěng le.</span><br>It got cold.</p>'},
  {lv:'HSK 1',t:'Measure Words',cn:'量词',py:'liàngcí',f:'Specific measure words must be used between numbers and nouns.',en:'one person',b:'<p>Chinese uses specific measure words (量词) between numbers and nouns.</p><p class="mt-2"><span class="fc font-bold text-lg">一个人</span><br><span style="color:var(--muted)">yí gè rén</span><br>one person</p><p><span class="fc font-bold text-lg">两本书</span><br><span style="color:var(--muted)">liǎng běn shū</span><br>two books</p><p><span class="fc font-bold text-lg">三杯水</span><br><span style="color:var(--muted)">sān bēi shuǐ</span><br>three cups of water</p><p class="mt-2">Common measure words: 个 (general), 本 (books), 杯 (drinks), 张 (paper/tables), 只 (animals), 条 (long objects)</p>'},
  {lv:'HSK 2',t:'The 比 Comparison',cn:'比',py:'bǐ',f:'Used to compare two things, like "than" in English.',en:'He is taller than me.',b:'<p><b>Structure:</b> A + 比 + B + adjective</p><p class="mt-2"><span class="fc font-bold text-lg">他比我高。</span><br><span style="color:var(--muted)">Tā bǐ wǒ gāo.</span><br>He is taller than me.</p><p><span class="fc font-bold text-lg">今天比昨天冷。</span><br><span style="color:var(--muted)">Jīntiān bǐ zuótiān lěng.</span><br>Today is colder than yesterday.</p><p class="mt-2">For "more specific": A + 比 + B + adj + 多了/一点儿</p><p><span class="fc font-bold text-lg">这个比那个大多了。</span><br><span style="color:var(--muted)">Zhège bǐ nàge dà duō le.</span><br>This is much bigger than that.</p>'},
  {lv:'HSK 2',t:'The 把 Construction',cn:'把',py:'bǎ',f:'Emphasizes the handling or disposal of an object.',en:'I opened the door.',b:'<p><b>Structure:</b> Subject + 把 + Object + Verb + Complement</p><p>把 shifts the object before the verb to emphasize how it is handled.</p><p class="mt-2"><span class="fc font-bold text-lg">我把门打开了。</span><br><span style="color:var(--muted)">Wǒ bǎ mén dǎkāi le.</span><br>I opened the door.</p><p><span class="fc font-bold text-lg">请把书放在桌子上。</span><br><span style="color:var(--muted)">Qǐng bǎ shū fàng zài zhuōzi shàng.</span><br>Please put the book on the table.</p>'},
  {lv:'HSK 2',t:'Result Complements',cn:'结果补语',py:'jiéguǒ bǔyǔ',f:'Show the result of an action using verb + complement.',en:'I saw it.',b:'<p>Result complements follow a verb to indicate the outcome.</p><p class="mt-2"><b>Common complements:</b> 到 (arrive/succeed), 完 (finish), 好 (complete well), 见 (perceive), 懂 (understand)</p><p><span class="fc font-bold text-lg">我看到了。</span><br><span style="color:var(--muted)">Wǒ kàn dào le.</span><br>I saw it. (look + arrive)</p><p><span class="fc font-bold text-lg">他吃完了。</span><br><span style="color:var(--muted)">Tā chī wán le.</span><br>He finished eating. (eat + finish)</p><p><span class="fc font-bold text-lg">我听懂了。</span><br><span style="color:var(--muted)">Wǒ tīng dǒng le.</span><br>I understood. (listen + understand)</p>'},
  {lv:'HSK 3',t:'The Adverb 就',cn:'就',py:'jiù',f:'Indicates earliness, immediacy, or logical connection.',en:'He came as early as 7 o\'clock.',b:'<p>就 has several uses:</p><p><b>1) Earlier than expected:</b></p><p><span class="fc font-bold text-lg">他七点就来了。</span><br><span style="color:var(--muted)">Tā qī diǎn jiù lái le.</span><br>He came as early as 7 o\'clock.</p><p class="mt-1"><b>2) Then / as a result:</b></p><p><span class="fc font-bold text-lg">如果下雨，我就不去。</span><br><span style="color:var(--muted)">Rúguǒ xiàyǔ, wǒ jiù bú qù.</span><br>If it rains, then I won\'t go.</p><p class="mt-1"><b>3) Exactly / precisely:</b></p><p><span class="fc font-bold text-lg">这就是我的书。</span><br><span style="color:var(--muted)">Zhè jiù shì wǒ de shū.</span><br>This is precisely my book.</p>'},
  {lv:'HSK 3',t:'The 除了...以外 Structure',cn:'除了...以外',py:'chúle...yǐwài',f:'"Besides / except" — includes or excludes something.',en:'Besides English, he also knows French.',b:'<p>Two meanings depending on context:</p><p><b>1) Including (also):</b> 除了...以外，还...</p><p><span class="fc font-bold text-lg">除了英语以外，他还会法语。</span><br><span style="color:var(--muted)">Chúle Yīngyǔ yǐwài, tā hái huì Fǎyǔ.</span><br>Besides English, he also knows French.</p><p class="mt-2"><b>2) Excluding (but not):</b> 除了...以外，都...</p><p><span class="fc font-bold text-lg">除了他以外，大家都来了。</span><br><span style="color:var(--muted)">Chúle tā yǐwài, dàjiā dōu lái le.</span><br>Everyone came except him.</p>'},
  {lv:'HSK 3',t:'Comparative with 没有',cn:'没有...那么',py:'méiyǒu...nàme',f:'"Not as...as" — make negative comparisons.',en:'I am not as tall as him.',b:'<p><b>Structure:</b> A + 没有 + B + 那么 + adjective</p><p>This means "A is not as adjective as B."</p><p class="mt-2"><span class="fc font-bold text-lg">我没有他那么高。</span><br><span style="color:var(--muted)">Wǒ méiyǒu tā nàme gāo.</span><br>I am not as tall as him.</p><p><span class="fc font-bold text-lg">今天没有昨天那么冷。</span><br><span style="color:var(--muted)">Jīntiān méiyǒu zuótiān nàme lěng.</span><br>Today is not as cold as yesterday.</p>'},
  {lv:'HSK 3',t:'The 一点儿 Structure',cn:'一点儿',py:'yìdiǎnr',f:'"A little bit" — small amount or slight degree.',en:'I have a little money.',b:'<p>一点儿 can be used in several ways:</p><p><b>1) A small quantity:</b></p><p><span class="fc font-bold text-lg">我有一点儿钱。</span><br><span style="color:var(--muted)">Wǒ yǒu yìdiǎnr qián.</span><br>I have a little money.</p><p class="mt-1"><b>2) Slightly more/less (after adjective):</b></p><p><span class="fc font-bold text-lg">大一点儿</span><br><span style="color:var(--muted)">dà yìdiǎnr</span><br>a little bigger</p><p class="mt-1"><b>3) "Not at all" (negative):</b> 一点儿 + 都 + 不</p><p><span class="fc font-bold text-lg">我一点儿都不累。</span><br><span style="color:var(--muted)">Wǒ yìdiǎnr dōu bú lèi.</span><br>I\'m not tired at all.</p>'},
  {lv:'HSK 3',t:'The 是...的 Focus Structure',cn:'是...的',py:'shì...de',f:'Emphasize a specific aspect of a past action.',en:'He came to China last year.',b:'<p>Use 是...的 to emphasize <b>time, place, manner, or purpose</b> of a past event.</p><p><b>Structure:</b> 是 + emphasized part + verb + 的</p><p class="mt-2"><span class="fc font-bold text-lg">他是去年来的中国。</span><br><span style="color:var(--muted)">Tā shì qùnián lái de Zhōngguó.</span><br>He came to China <b>last year</b>.</p><p><span class="fc font-bold text-lg">我是走路来的。</span><br><span style="color:var(--muted)">Wǒ shì zǒulù lái de.</span><br>I came <b>by walking</b>.</p><p><span class="fc font-bold text-lg">你是跟谁一起去的？</span><br><span style="color:var(--muted)">Nǐ shì gēn shéi yìqǐ qù de?</span><br>Who did you go <b>with</b>?</p>'},
  {lv:'HSK 3',t:'Directional Complements',cn:'趋向补语',py:'qūxiàng bǔyǔ',f:'Indicate direction of movement: come/go + direction.',en:'come up / go up',b:'<p>Directional complements show movement toward or away from the speaker.</p><p class="mt-2"><b>Simple:</b> 来 (toward) / 去 (away)</p><p><span class="fc font-bold text-lg">上来 / 上去</span><br><span style="color:var(--muted)">shànglái / shàngqù</span><br>come up / go up</p><p><span class="fc font-bold text-lg">进来 / 进去</span><br><span style="color:var(--muted)">jìnlái / jìnqù</span><br>come in / go in</p><p><span class="fc font-bold text-lg">回来 / 回去</span><br><span style="color:var(--muted)">huílái / huíqù</span><br>come back / go back</p><p class="mt-2"><b>Example:</b></p><p><span class="fc font-bold text-lg">他走上来了。</span><br><span style="color:var(--muted)">Tā zǒu shànglái le.</span><br>He walked up (toward speaker).</p>'},
  {lv:'HSK 3',t:'The 被 Passive Voice',cn:'被',py:'bèi',f:'Form the passive voice — "something is done by someone."',en:'My phone was stolen.',b:'<p><b>Structure:</b> Subject + 被 + agent + verb + complement</p><p class="mt-2"><span class="fc font-bold text-lg">我的手机被偷了。</span><br><span style="color:var(--muted)">Wǒ de shǒujī bèi tōu le.</span><br>My phone was stolen.</p><p><span class="fc font-bold text-lg">他被老师批评了。</span><br><span style="color:var(--muted)">Tā bèi lǎoshī pīpíng le.</span><br>He was criticized by the teacher.</p><p class="mt-2">In spoken Chinese, 让 or 叫 can replace 被:</p><p><span class="fc font-bold text-lg">我的钱让人拿走了。</span><br><span style="color:var(--muted)">Wǒ de qián ràng rén ná zǒu le.</span><br>My money was taken by someone.</p>'},
  {lv:'HSK 3',t:'The 连...都/也 Structure',cn:'连...都/也',py:'lián...dōu/yě',f:'"Even" — emphasizing an extreme case.',en:'Even the teacher doesn\'t know.',b:'<p><b>Structure:</b> 连 + noun/verb + 都/也 + negative</p><p>Emphasizes that even the most basic/elementary item is included or excluded.</p><p class="mt-2"><span class="fc font-bold text-lg">连老师都不知道。</span><br><span style="color:var(--muted)">Lián lǎoshī dōu bù zhīdao.</span><br>Even the teacher doesn\'t know.</p><p><span class="fc font-bold text-lg">他连水都不喝。</span><br><span style="color:var(--muted)">Tā lián shuǐ dōu bù hē.</span><br>He doesn\'t even drink water.</p><p><span class="fc font-bold text-lg">我连一个字都没说。</span><br><span style="color:var(--muted)">Wǒ lián yí gè zì dōu méi shuō.</span><br>I didn\'t even say a single word.</p>'},
  {lv:'HSK 3',t:'The 越...越 Pattern',cn:'越...越',py:'yuè...yuè',f:'"The more... the more..." — a correlative comparison.',en:'The rain is getting heavier and heavier.',b:'<p><b>Structure:</b> 越 + verb/adjective + 越 + verb/adjective</p><p>Indicates that as one thing increases, another also increases.</p><p class="mt-2"><span class="fc font-bold text-lg">雨越下越大。</span><br><span style="color:var(--muted)">Yǔ yuè xià yuè dà.</span><br>The rain is getting heavier and heavier.</p><p><span class="fc font-bold text-lg">中文越学越有意思。</span><br><span style="color:var(--muted)">Zhōngwén yuè xué yuè yǒu yìsi.</span><br>The more Chinese you study, the more interesting it gets.</p><p><span class="fc font-bold text-lg">他越跑越快。</span><br><span style="color:var(--muted)">Tā yuè pǎo yuè kuài.</span><br>He ran faster and faster.</p>'},
  {lv:'HSK 4',t:'The 不仅...而且 Structure',cn:'不仅...而且',py:'bù jǐn...ér qiě',f:'"Not only... but also" — adding emphasis.',en:'He not only speaks Chinese, but also writes it well.',b:'<p><b>Structure:</b> 不仅 + A + 而且 + B</p><p>Links two related points, emphasizing that both are true.</p><p class="mt-2"><span class="fc font-bold text-lg">他不仅会说中文，而且写得很好。</span><br><span style="color:var(--muted)">Tā bùjǐn huì shuō Zhōngwén, érqiě xiě de hěn hǎo.</span><br>He not only speaks Chinese, but also writes it well.</p><p><span class="fc font-bold text-lg">这个地方不仅风景优美，而且气候宜人。</span><br><span style="color:var(--muted)">Zhège dìfang bùjǐn fēngjǐng yōuměi, érqiě qìhòu yírén.</span><br>This place not only has beautiful scenery, but also has a pleasant climate.</p>'},
  {lv:'HSK 4',t:'The 一边...一边 Structure',cn:'一边...一边',py:'yì biān...yì biān',f:'"While / at the same time" — two simultaneous actions.',en:'I listen to music while eating.',b:'<p><b>Structure:</b> 一边 + verb1 + 一边 + verb2</p><p>Indicates two actions performed simultaneously by the same subject.</p><p class="mt-2"><span class="fc font-bold text-lg">我一边吃饭一边听音乐。</span><br><span style="color:var(--muted)">Wǒ yì biān chīfàn yì biān tīng yīnyuè.</span><br>I eat while listening to music.</p><p><span class="fc font-bold text-lg">他一边走路一边看手机。</span><br><span style="color:var(--muted)">Tā yì biān zǒulù yì biān kàn shǒujī.</span><br>He walks while looking at his phone.</p><p><span class="fc font-bold text-lg">我们一边喝茶一边聊天。</span><br><span style="color:var(--muted)">Wǒmen yì biān hē chá yì biān liáotiān.</span><br>We chat while drinking tea.</p>'},
  {lv:'HSK 4',t:'The 却 Adversative Adverb',cn:'却',py:'què',f:'"Yet / however" — expresses contrast or unexpectedness.',en:'He said he would come, yet he didn\'t.',b:'<p>却 is placed after the subject and before the verb. It is milder and more literary than 但是.</p><p class="mt-2"><span class="fc font-bold text-lg">他说要来，却没有来。</span><br><span style="color:var(--muted)">Tā shuō yào lái, què méiyǒu lái.</span><br>He said he would come, yet he didn\'t come.</p><p><span class="fc font-bold text-lg">这件衣服看起来很便宜，却要一千块。</span><br><span style="color:var(--muted)">Zhè jiàn yīfu kàn qǐlai hěn piányi, què yào yì qiān kuài.</span><br>This piece of clothing looks cheap, yet it costs a thousand yuan.</p>'},
  {lv:'HSK 4',t:'The 从来 Adverb',cn:'从来',py:'cóng lái',f:'"Always / never (with negative)" — from past to present.',en:'I have never been to Beijing.',b:'<p>从来 is used with 都 for emphasis. With a negative, it means "never." With a positive, it means "always."</p><p class="mt-2"><span class="fc font-bold text-lg">我从来没有去过北京。</span><br><span style="color:var(--muted)">Wǒ cónglái méiyǒu qù guò Běijīng.</span><br>I have never been to Beijing.</p><p><span class="fc font-bold text-lg">他从来不迟到。</span><br><span style="color:var(--muted)">Tā cónglái bù chídào.</span><br>He is never late.</p><p><span class="fc font-bold text-lg">我从来都相信你。</span><br><span style="color:var(--muted)">Wǒ cónglái dōu xiāngxìn nǐ.</span><br>I have always believed in you.</p>'},
  {lv:'HSK 5',t:'The 之所以...是因为 Structure',cn:'之所以...是因为',py:'zhī suǒ yǐ...shì yīn wèi',f:'"The reason why... is that..." — formal causal emphasis.',en:'The reason why he succeeded is that he worked hard.',b:'<p><b>Structure:</b> 之所以 + result + 是因为 + reason</p><p>This is a more formal, emphatic way to state cause and effect, often used in writing.</p><p class="mt-2"><span class="fc font-bold text-lg">他之所以成功，是因为他非常努力。</span><br><span style="color:var(--muted)">Tā zhī suǒ yǐ chénggōng, shì yīnwèi tā fēicháng nǔlì.</span><br>The reason why he succeeded is that he worked very hard.</p><p><span class="fc font-bold text-lg">我之所以学中文，是因为对中国文化感兴趣。</span><br><span style="color:var(--muted)">Wǒ zhī suǒ yǐ xué Zhōngwén, shì yīnwèi duì Zhōngguó wénhuà gǎn xìngqù.</span><br>The reason why I study Chinese is that I am interested in Chinese culture.</p>'},
  {lv:'HSK 5',t:'The 既然...就 Structure',cn:'既然...就',py:'jì rán...jiù',f:'"Since... then" — logical deduction based on a premise.',en:'Since you have decided, then go ahead.',b:'<p><b>Structure:</b> 既然 + premise + 就 + conclusion</p><p>States a premise that is accepted as true, then draws a logical conclusion.</p><p class="mt-2"><span class="fc font-bold text-lg">你既然决定了，就去做吧。</span><br><span style="color:var(--muted)">Nǐ jìrán juédìng le, jiù qù zuò ba.</span><br>Since you have decided, then go ahead and do it.</p><p><span class="fc font-bold text-lg">既然大家都同意了，我们就开始吧。</span><br><span style="color:var(--muted)">Jìrán dàjiā dōu tóngyì le, wǒmen jiù kāishǐ ba.</span><br>Since everyone agrees, let us start.</p>'},
  {lv:'HSK 5',t:'The 否则 Conjunction',cn:'否则',py:'fǒu zé',f:'"Otherwise / or else" — indicating a consequence.',en:'Hurry up, otherwise we will be late.',b:'<p><b>Structure:</b> [action] + 否则 + [negative consequence]</p><p>否则 is used to indicate what will happen if a suggested action is not taken. Similar to 要不然.</p><p class="mt-2"><span class="fc font-bold text-lg">快点，否则我们就要迟到了。</span><br><span style="color:var(--muted)">Kuài diǎn, fǒuzé wǒmen jiù yào chídào le.</span><br>Hurry up, otherwise we will be late.</p><p><span class="fc font-bold text-lg">你必须好好学习，否则考试会不及格。</span><br><span style="color:var(--muted)">Nǐ bìxū hǎohǎo xuéxí, fǒuzé kǎoshì huì bù jígé.</span><br>You must study hard, otherwise you will fail the exam.</p>'},
  {lv:'HSK 5',t:'The 无论...都 Structure',cn:'无论...都',py:'wú lùn...dōu',f:'"No matter / regardless" — universal condition.',en:'No matter how busy he is, he always exercises.',b:'<p><b>Structure:</b> 无论 + question word/phrase + 都/也 + result</p><p>Expresses that a result holds true under any condition.</p><p class="mt-2"><span class="fc font-bold text-lg">无论多忙，他都坚持锻炼。</span><br><span style="color:var(--muted)">Wúlùn duō máng, tā dōu jiānchí duànliàn.</span><br>No matter how busy he is, he always exercises.</p><p><span class="fc font-bold text-lg">无论谁来了，都不要开门。</span><br><span style="color:var(--muted)">Wúlùn shuí lái le, dōu búyào kāimén.</span><br>No matter who comes, do not open the door.</p>'},
  {lv:'HSK 6',t:'The 之所以...是因为 Structure (Advanced)',cn:'之所以...是因为',py:'zhī suǒ yǐ...shì yīn wèi',f:'"The reason why... is that..." — formal written emphasis.',en:'The reason why the experiment failed is that the data was insufficient.',b:'<p><b>Structure:</b> 之所以 + result + 是因为 + reason</p><p>This advanced structure is very common in formal writing and academic Chinese.</p><p class="mt-2"><span class="fc font-bold text-lg">实验之所以失败，是因为数据不够充分。</span><br><span style="color:var(--muted)">Shíyàn zhī suǒ yǐ shībài, shì yīnwèi shùjù bú gòu chōngfèn.</span><br>The reason why the experiment failed is that the data was insufficient.</p><p><span class="fc font-bold text-lg">这种观点之所以流行，是因为它符合人们的直觉。</span><br><span style="color:var(--muted)">Zhè zhǒng guāndiǎn zhī suǒ yǐ liúxíng, shì yīnwèi tā fúhé rénmen de zhíjué.</span><br>The reason this view is popular is that it fits people\'s intuition.</p>'},
  {lv:'HSK 6',t:'The 万一 Conjunction',cn:'万一',py:'wàn yī',f:'"In case / just in case" — a small probability with serious consequence.',en:'Take an umbrella in case it rains.',b:'<p>万一 introduces a low-probability but potentially troublesome event. It often carries a tone of warning.</p><p class="mt-2"><span class="fc font-bold text-lg">带上伞，万一下雨呢。</span><br><span style="color:var(--muted)">Dài shàng sǎn, wànyī xiàyǔ ne.</span><br>Take an umbrella, in case it rains.</p><p><span class="fc font-bold text-lg">万一出了问题，你要负全部责任。</span><br><span style="color:var(--muted)">Wànyī chū le wèntí, nǐ yào fù quánbù zérèn.</span><br>In case something goes wrong, you will bear full responsibility.</p>'},
  {lv:'HSK 6',t:'The 宁可...也不 Structure',cn:'宁可...也不',py:'nìng kě...yě bù',f:'"Would rather... than" — expressing a strong preference.',en:'I would rather walk than take a taxi.',b:'<p><b>Structure:</b> 宁可 + A + 也不 + B</p><p>Expresses that the speaker prefers A over B, often with an emotional tone of determination.</p><p class="mt-2"><span class="fc font-bold text-lg">我宁可走路，也不坐出租车。</span><br><span style="color:var(--muted)">Wǒ nìngkě zǒulù, yě bú zuò chūzūchē.</span><br>I would rather walk than take a taxi.</p><p><span class="fc font-bold text-lg">他宁可自己吃亏，也不让别人受委屈。</span><br><span style="color:var(--muted)">Tā nìngkě zìjǐ chīkuī, yě bú ràng biérén shòu wěiqu.</span><br>He would rather suffer losses himself than let others be wronged.</p>'},
  {lv:'HSK 6',t:'The 况且 Conjunction',cn:'况且',py:'kuàng qiě',f:'"Moreover / besides" — adding an additional, stronger reason.',en:'It is late, and moreover it is raining. Let us stay.',b:'<p>况且 is used to add an additional reason that further supports a conclusion. It is more formal than 而且.</p><p class="mt-2"><span class="fc font-bold text-lg">天已经晚了，况且又下着雨，我们就别出去了。</span><br><span style="color:var(--muted)">Tiān yǐjīng wǎn le, kuàngqiě yòu xià zhe yǔ, wǒmen jiù bié chūqù le.</span><br>It is already late, and moreover it is raining, so let us not go out.</p><p><span class="fc font-bold text-lg">这个方案成本太高，况且效果也不确定。</span><br><span style="color:var(--muted)">Zhège fāng’àn chéngběn tài gāo, kuàngqiě xiàoguǒ yě bú quèdìng.</span><br>This plan costs too much, and moreover the effect is uncertain.</p>'},
  {lv:'HSK 7',t:'The 乃至 Conjunction',cn:'乃至',py:'nǎi zhì',f:'"Even / up to" — extending to an extreme degree.',en:'This issue concerns the whole society, even the entire country.',b:'<p>乃至 is a formal conjunction that extends a statement to a more extreme or comprehensive level. Equivalent to 甚至 but more literary.</p><p class="mt-2"><span class="fc font-bold text-lg">这个问题关系到整个社会乃至国家的利益。</span><br><span style="color:var(--muted)">Zhège wèntí guānxì dào zhěnggè shèhuì nǎizhì guójiā de lìyì.</span><br>This issue concerns the whole society and even the interests of the nation.</p><p><span class="fc font-bold text-lg">他精通英语、法语乃至拉丁语。</span><br><span style="color:var(--muted)">Tā jīngtōng Yīngyǔ, Fǎyǔ nǎizhì Lādīngyǔ.</span><br>He is proficient in English, French, and even Latin.</p>'},
  {lv:'HSK 7',t:'The 鉴于 Preposition',cn:'鉴于',py:'jiàn yú',f:'"In view of / given that" — formal premise.',en:'Given the current situation, we must take immediate action.',b:'<p>鉴于 is used in formal writing to introduce a consideration or fact that leads to a decision.</p><p class="mt-2"><span class="fc font-bold text-lg">鉴于目前的情况，我们必须立即采取行动。</span><br><span style="color:var(--muted)">Jiànyú mùqián de qíngkuàng, wǒmen bìxū lìjí cǎiqǔ xíngdòng.</span><br>In view of the current situation, we must take immediate action.</p><p><span class="fc font-bold text-lg">鉴于他的突出贡献，公司决定给予特别奖励。</span><br><span style="color:var(--muted)">Jiànyú tā de tūchū gòngxiàn, gōngsī juédìng jǐyǔ tèbié jiǎnglì.</span><br>In view of his outstanding contributions, the company decided to give a special award.</p>'},
  {lv:'HSK 7',t:'The 固然 Conjunction',cn:'固然',py:'gù rán',f:'"Admittedly / it is true that" — conceding a point.',en:'Admittedly this method is simple, but it is not effective enough.',b:'<p>固然 acknowledges a point before introducing a contrasting or stronger point. Similar to "it is true that... but..."</p><p class="mt-2"><span class="fc font-bold text-lg">这种方法固然简单，但是效果不够理想。</span><br><span style="color:var(--muted)">Zhè zhǒng fāngfǎ gùrán jiǎndān, dànshì xiàoguǒ bú gòu lǐxiǎng.</span><br>Admittedly this method is simple, but the results are not ideal enough.</p><p><span class="fc font-bold text-lg">金钱固然重要，但健康更加重要。</span><br><span style="color:var(--muted)">Jīnqián gùrán zhòngyào, dàn jiànkāng gèngjiā zhòngyào.</span><br>Money is admittedly important, but health is even more important.</p>'},
  {lv:'HSK 8',t:'The 与其...不如 Structure',cn:'与其...不如',py:'yǔ qí...bù rú',f:'"Rather than... it is better to..." — expressing preference.',en:'Rather than waiting, it is better to take action ourselves.',b:'<p><b>Structure:</b> 与其 + A + 不如 + B</p><p>Expresses that B is a better choice than A. This is a more formal and persuasive structure.</p><p class="mt-2"><span class="fc font-bold text-lg">与其坐等，不如自己行动。</span><br><span style="color:var(--muted)">Yǔqí zuò děng, bùrú zìjǐ xíngdòng.</span><br>Rather than sitting and waiting, it is better to take action ourselves.</p><p><span class="fc font-bold text-lg">与其买便宜货，不如买质量好的。</span><br><span style="color:var(--muted)">Yǔqí mǎi piányi huò, bùrú mǎi zhìliàng hǎo de.</span><br>Rather than buying cheap goods, it is better to buy quality ones.</p>'},
  {lv:'HSK 8',t:'The 尚且...何况 Structure',cn:'尚且...何况',py:'shàng qiě...hé kuàng',f:'"Even... let alone" — rhetorical comparison.',en:'Even a professional cannot do it, let alone a beginner.',b:'<p><b>Structure:</b> (even) A + 尚且 + predicate + 何况 + B</p><p>Argues that if A cannot do something, then even less can B. Logical escalation.</p><p class="mt-2"><span class="fc font-bold text-lg">专业选手尚且做不好，何况新手呢。</span><br><span style="color:var(--muted)">Zhuānyè xuǎnshǒu shàngqiě zuò bù hǎo, hékuàng xīnshǒu ne.</span><br>Even a professional cannot do it well, let alone a beginner.</p><p><span class="fc font-bold text-lg">大人尚且拿不动，何况小孩呢。</span><br><span style="color:var(--muted)">Dàrén shàngqiě ná bú dòng, hékuàng xiǎohái ne.</span><br>Even an adult cannot lift it, let alone a child.</p>'},
  {lv:'HSK 8',t:'The 基于 Preposition',cn:'基于',py:'jī yú',f:'"Based on / due to" — establishing grounds.',en:'Based on the above analysis, we propose the following suggestions.',b:'<p>基于 introduces the basis or grounds for an action, opinion, or decision. Very common in formal writing.</p><p class="mt-2"><span class="fc font-bold text-lg">基于以上分析，我们提出以下建议。</span><br><span style="color:var(--muted)">Jīyú yǐshàng fēnxī, wǒmen tíchū yǐxià jiànyì.</span><br>Based on the above analysis, we propose the following suggestions.</p><p><span class="fc font-bold text-lg">基于安全考虑，所有乘客必须系好安全带。</span><br><span style="color:var(--muted)">Jīyú ānquán kǎolǜ, suǒyǒu chéngkè bìxū jì hǎo ānquán dài.</span><br>Based on safety considerations, all passengers must fasten their seat belts.</p>'},
  {lv:'HSK 9',t:'The 抑或 Conjunction',cn:'抑或',py:'yì huò',f:'"Or / or perhaps" — presenting alternatives in formal writing.',en:'We should consider whether to continue or to terminate the plan.',b:'<p>抑或 is a formal, literary conjunction used to present alternative possibilities, more elegant than 或者.</p><p class="mt-2"><span class="fc font-bold text-lg">我们应该考虑继续执行，抑或终止这个计划。</span><br><span style="color:var(--muted)">Wǒmen yīnggāi kǎolǜ jìxù zhíxíng, yìhuò zhōngzhǐ zhège jìhuà.</span><br>We should consider whether to continue implementing or to terminate this plan.</p><p><span class="fc font-bold text-lg">他的动机是出于善意，抑或另有图谋？</span><br><span style="color:var(--muted)">Tā de dòngjī shì chūyú shànyì, yìhuò lìng yǒu túmóu?</span><br>Is his motive out of goodwill, or does he have other intentions?</p>'},
  {lv:'HSK 9',t:'The 无不 Double Negative',cn:'无不',py:'wú bù',f:'"There is none who does not / everyone" — universal affirmative.',en:'Everyone who heard the news was shocked.',b:'<p>无不 is a double negative (无 + 不) that creates a strong positive. It means "everyone does / there is no one who does not." Highly literary.</p><p class="mt-2"><span class="fc font-bold text-lg">听到这个消息，大家无不感到震惊。</span><br><span style="color:var(--muted)">Tīng dào zhège xiāoxi, dàjiā wú bù gǎndào zhènjīng.</span><br>Upon hearing the news, everyone was shocked.</p><p><span class="fc font-bold text-lg">他的演讲感人至深，听众无不为之动容。</span><br><span style="color:var(--muted)">Tā de yǎnjiǎng gǎnrén zhì shēn, tīngzhòng wú bù wèi zhī dòngróng.</span><br>His speech was deeply moving, and everyone in the audience was touched by it.</p>'},
  {lv:'HSK 9',t:'The 可谓 Expression',cn:'可谓',py:'kě wèi',f:'"It can be said that / truly is" — emphatic statement.',en:'He can truly be called a master of calligraphy.',b:'<p>可谓 is used in formal/literary Chinese to introduce a strong evaluation or characterization. It combines 可 (can) + 谓 (call/say).</p><p class="mt-2"><span class="fc font-bold text-lg">他堪称书法大师，其作品可谓出神入化。</span><br><span style="color:var(--muted)">Tā kānchēng shūfǎ dàshī, qí zuòpǐn kěwèi chūshén rùhuà.</span><br>He can be called a master of calligraphy; his works can truly be said to reach the pinnacle of perfection.</p><p><span class="fc font-bold text-lg">这次展览可谓空前绝后。</span><br><span style="color:var(--muted)">Zhè cì zhǎnlǎn kěwèi kōngqián juéhòu.</span><br>This exhibition can truly be called unprecedented.</p>'},
  {lv:'HSK 1',t:'The 会 Modal Verb',cn:'会',py:'huì',f:'"Can / will" — expresses ability or future possibility.',en:'I can speak Chinese.',b:'<p>会 has two main meanings:</p><p><b>1) Ability (learned skill):</b></p><p><span class="fc font-bold text-lg">我会说中文。</span><br><span style="color:var(--muted)">Wǒ huì shuō Zhōngwén.</span><br>I can speak Chinese.</p><p class="mt-2"><b>2) Future possibility:</b></p><p><span class="fc font-bold text-lg">明天会下雨。</span><br><span style="color:var(--muted)">Míngtiān huì xiàyǔ.</span><br>It will rain tomorrow.</p><p><span class="fc font-bold text-lg">他不会来了。</span><br><span style="color:var(--muted)">Tā bú huì lái le.</span><br>He won\'t come.</p>'},
  {lv:'HSK 1',t:'The 很 Adverb',cn:'很',py:'hěn',f:'"Very" — used before adjectives; also serves as a linking verb.',en:'It is very good.',b:'<p>很 is the most common Chinese adverb. It is used before adjectives. In Chinese, adjectives can function as verbs, so 很 often simply connects the subject and adjective without meaning "very."</p><p class="mt-2"><span class="fc font-bold text-lg">很好。</span><br><span style="color:var(--muted)">Hěn hǎo.</span><br>Good / Very good.</p><p><span class="fc font-bold text-lg">她很高。</span><br><span style="color:var(--muted)">Tā hěn gāo.</span><br>She is tall.</p><p><span class="fc font-bold text-lg">这个苹果很大。</span><br><span style="color:var(--muted)">Zhège píngguǒ hěn dà.</span><br>This apple is big.</p>'},
  {lv:'HSK 2',t:'The 在 Progressive',cn:'正在',py:'zhèngzài',f:'"In the process of" — indicates an ongoing action.',en:'I am eating.',b:'<p><b>Structure:</b> Subject + 正在/在 + verb</p><p>正在 emphasizes the action is in progress right now. 在 is more casual.</p><p class="mt-2"><span class="fc font-bold text-lg">我正在吃饭。</span><br><span style="color:var(--muted)">Wǒ zhèngzài chīfàn.</span><br>I am eating.</p><p><span class="fc font-bold text-lg">他在看书。</span><br><span style="color:var(--muted)">Tā zài kàn shū.</span><br>He is reading a book.</p><p><span class="fc font-bold text-lg">你在做什么？</span><br><span style="color:var(--muted)">Nǐ zài zuò shénme?</span><br>What are you doing?</p>'},
  {lv:'HSK 2',t:'The 要 Modal Verb',cn:'要',py:'yào',f:'"Want to / going to" — expresses desire or future intention.',en:'I want to go to China.',b:'<p>要 is a versatile modal verb:</p><p><b>1) Want / desire:</b></p><p><span class="fc font-bold text-lg">我要去中国。</span><br><span style="color:var(--muted)">Wǒ yào qù Zhōngguó.</span><br>I want to go to China.</p><p class="mt-2"><b>2) Going to (near future):</b></p><p><span class="fc font-bold text-lg">要下雨了。</span><br><span style="color:var(--muted)">Yào xiàyǔ le.</span><br>It\'s going to rain.</p><p class="mt-2"><b>Negative:</b> 不想 (don\'t want) vs 不要 (don\'t — stronger/command)</p><p><span class="fc font-bold text-lg">我不想吃。</span><br><span style="color:var(--muted)">Wǒ bù xiǎng chī.</span><br>I don\'t want to eat.</p>'},
  {lv:'HSK 7',t:'The 从而 Conjunction',cn:'从而',py:'cóng ér',f:'"Thereby / thus" — indicating a resulting action.',en:'The company expanded, thereby creating more jobs.',b:'<p>从而 introduces a result or consequence that follows logically from the preceding action. Used in formal writing.</p><p class="mt-2"><span class="fc font-bold text-lg">公司扩大了规模，从而创造了更多就业机会。</span><br><span style="color:var(--muted)">Gōngsī kuòdà le guīmó, cóng’ér chuàngzào le gèng duō jiùyè jīhuì.</span><br>The company expanded its scale, thereby creating more job opportunities.</p><p><span class="fc font-bold text-lg">他努力学习，从而考上了理想的大学。</span><br><span style="color:var(--muted)">Tā nǔlì xuéxí, cóng’ér kǎoshàng le lǐxiǎng de dàxué.</span><br>He studied hard, thus getting into his ideal university.</p>'},
  {lv:'HSK 7',t:'The 出于 Preposition',cn:'出于',py:'chū yú',f:'"Out of / due to" — indicating motive or reason.',en:'He did it out of kindness.',b:'<p>出于 introduces the motive, reason, or consideration behind an action. Common in formal contexts.</p><p class="mt-2"><span class="fc font-bold text-lg">他出于好心帮助了我。</span><br><span style="color:var(--muted)">Tā chūyú hǎoxīn bāngzhù le wǒ.</span><br>He helped me out of kindness.</p><p><span class="fc font-bold text-lg">出于安全考虑，会议延期了。</span><br><span style="color:var(--muted)">Chūyú ānquán kǎolǜ, huìyì yánqī le.</span><br>Due to safety considerations, the meeting was postponed.</p>'},
  {lv:'HSK 8',t:'The 乃至 Conjunction',cn:'乃至',py:'nǎi zhì',f:'"Even / and even" — extending to an extreme degree.',en:'The issue affects the city, the province, and even the whole country.',b:'<p>乃至 is a formal conjunction that extends a statement to a more extreme level. Similar to 甚至 but more literary.</p><p class="mt-2"><span class="fc font-bold text-lg">这个问题影响到城市、省份乃至整个国家。</span><br><span style="color:var(--muted)">Zhège wèntí yǐngxiǎng dào chéngshì, shěngfèn nǎizhì zhěnggè guójiā.</span><br>This issue affects the city, the province, and even the whole country.</p><p><span class="fc font-bold text-lg">他精通多国语言乃至古典拉丁文。</span><br><span style="color:var(--muted)">Tā jīngtōng duō guó yǔyán nǎizhì gǔdiǎn Lādīngwén.</span><br>He is proficient in multiple languages and even classical Latin.</p>'},
  {lv:'HSK 8',t:'The 以 Preposition',cn:'以',py:'yǐ',f:'"In order to / so as to" — indicating purpose or means.',en:'We must work hard in order to achieve our goals.',b:'<p>以 is a formal preposition used to express purpose or the means by which something is done. Very common in written Chinese.</p><p class="mt-2"><span class="fc font-bold text-lg">我们必须努力工作以达成目标。</span><br><span style="color:var(--muted)">Wǒmen bìxū nǔlì gōngzuò yǐ dáchéng mùbiāo.</span><br>We must work hard in order to achieve our goals.</p><p><span class="fc font-bold text-lg">以此证明，他确实有资格。</span><br><span style="color:var(--muted)">Yǐ cǐ zhèngmíng, tā quèshí yǒu zīgé.</span><br>Hereby it is proven that he is indeed qualified.</p>'},
  {lv:'HSK 9',t:'The 之于 Expression',cn:'之于',py:'zhī yú',f:'"In relation to / with regard to" — formal comparison.',en:'Knowledge is to the mind what light is to the eye.',b:'<p>之于 is a classical Chinese structure widely used in modern formal/literary writing. It relates two things, often in a comparative or proportional sense.</p><p class="mt-2"><span class="fc font-bold text-lg">知识之于心灵，犹如光明之于眼睛。</span><br><span style="color:var(--muted)">Zhīshi zhī yú xīnlíng, yóurú guāngmíng zhī yú yǎnjīng.</span><br>Knowledge is to the mind what light is to the eye.</p><p><span class="fc font-bold text-lg">诚信之于企业，如同根基之于大厦。</span><br><span style="color:var(--muted)">Chéngxìn zhī yú qǐyè, rútóng gēnjī zhī yú dàshà.</span><br>Integrity is to a business what the foundation is to a building.</p>'},
  {lv:'HSK 9',t:'The 及物 Verb Pattern',cn:'及物',py:'jí wù',f:'"Concerning / as for" — introducing a topic in formal discourse.',en:'As for this issue, we need further discussion.',b:'<p>及物 is used to introduce the object or topic of a discussion, similar to "regarding" or "with respect to" in formal English.</p><p class="mt-2"><span class="fc font-bold text-lg">及此问题，我们需要进一步讨论。</span><br><span style="color:var(--muted)">Jí cǐ wèntí, wǒmen xūyào jìnyíbù tǎolùn.</span><br>Regarding this issue, we need further discussion.</p><p><span class="fc font-bold text-lg">及其后果，大家应该都有所了解。</span><br><span style="color:var(--muted)">Jí qí hòuguǒ, dàjiā yīnggāi dōu yǒu suǒ liǎojiě.</span><br>As for its consequences, everyone should have some understanding.</p>'},
  {lv:'HSK 1',t:'The Question Particle 吗',cn:'吗',py:'ma',f:'"?" — turns a statement into a yes/no question.',en:'Are you a student?',b:'<p>Add 吗 to the end of any statement to form a simple yes/no question.</p><p class="mt-2"><span class="fc font-bold text-lg">你是学生吗？</span><br><span style="color:var(--muted)">Nǐ shì xuéshēng ma?</span><br>Are you a student?</p><p><span class="fc font-bold text-lg">你喜欢猫吗？</span><br><span style="color:var(--muted)">Nǐ xǐhuān māo ma?</span><br>Do you like cats?</p>'},
  {lv:'HSK 1',t:'The 也 Adverb',cn:'也',py:'yě',f:'"Also / too" — indicates something is also true.',en:'I am also a student.',b:'<p>也 is placed before the verb, not at the end of the sentence.</p><p class="mt-2"><span class="fc font-bold text-lg">我也是学生。</span><br><span style="color:var(--muted)">Wǒ yě shì xuéshēng.</span><br>I am also a student.</p><p><span class="fc font-bold text-lg">他喜欢喝茶，也喜欢喝咖啡。</span><br><span style="color:var(--muted)">Tā xǐhuān hē chá, yě xǐhuān hē kāfēi.</span><br>He likes to drink tea and also likes to drink coffee.</p>'},
  {lv:'HSK 1',t:'The 的 Possessive Particle',cn:'的',py:'de',f:'"\'s / of" — indicates possession or modification.',en:'my book',b:'<p>的 connects a modifier to a noun. It can show possession, describe quality, or link an adjective.</p><p class="mt-2"><span class="fc font-bold text-lg">我的书</span><br><span style="color:var(--muted)">wǒ de shū</span><br>my book</p><p><span class="fc font-bold text-lg">红色的苹果</span><br><span style="color:var(--muted)">hóngsè de píngguǒ</span><br>red apple</p><p><span class="fc font-bold text-lg">今天很冷，多穿一点儿衣服。</span><br><span style="color:var(--muted)">Jīntiān hěn lěng, duō chuān yìdiǎnr yīfu.</span><br>Today is cold, wear a bit more clothes.</p>'},
  {lv:'HSK 2',t:'The 过 Experiential Particle',cn:'过',py:'guò',f:'"Have ever / have never" — indicates past experience.',en:'I have been to Beijing.',b:'<p>Verb + 过 indicates that someone has had the experience of doing something at least once.</p><p class="mt-2"><span class="fc font-bold text-lg">我去过北京。</span><br><span style="color:var(--muted)">Wǒ qù guò Běijīng.</span><br>I have been to Beijing.</p><p><span class="fc font-bold text-lg">你吃过中国菜吗？</span><br><span style="color:var(--muted)">Nǐ chī guò Zhōngguó cài ma?</span><br>Have you eaten Chinese food?</p><p><span class="fc font-bold text-lg">我没看过这部电影。</span><br><span style="color:var(--muted)">Wǒ méi kàn guò zhè bù diànyǐng.</span><br>I have not seen this movie.</p>'},
  {lv:'HSK 2',t:'The 给 Dative Verb',cn:'给',py:'gěi',f:'"To give / for" — introduces the recipient of an action.',en:'I give a book to him.',b:'<p>给 can be used as a main verb meaning "to give" or as a preposition meaning "for / to" introducing the recipient.</p><p class="mt-2"><span class="fc font-bold text-lg">我给你一本书。</span><br><span style="color:var(--muted)">Wǒ gěi nǐ yì běn shū.</span><br>I give you a book.</p><p><span class="fc font-bold text-lg">他给我打电话。</span><br><span style="color:var(--muted)">Tā gěi wǒ dǎ diànhuà.</span><br>He calls me.</p>'},
  {lv:'HSK 2',t:'The 从 Preposition',cn:'从',py:'cóng',f:'"From" — indicates the starting point.',en:'I come from America.',b:'<p>从 indicates the origin or starting point of an action, whether spatial or temporal.</p><p class="mt-2"><span class="fc font-bold text-lg">我从美国来。</span><br><span style="color:var(--muted)">Wǒ cóng Měiguó lái.</span><br>I come from America.</p><p><span class="fc font-bold text-lg">我从早上八点工作到下午五点。</span><br><span style="color:var(--muted)">Wǒ cóng zǎoshang bā diǎn gōngzuò dào xiàwǔ wǔ diǎn.</span><br>I work from 8am to 5pm.</p>'},
  {lv:'HSK 3',t:'The 才 Adverb',cn:'才',py:'cái',f:'"Only then / just" — indicates lateness or insufficiency.',en:'He only arrived at 10 o\'clock.',b:'<p>才 has two opposite meanings depending on context:</p><p><b>1) Later than expected:</b></p><p><span class="fc font-bold text-lg">他十点才来。</span><br><span style="color:var(--muted)">Tā shí diǎn cái lái.</span><br>He only came at 10 o\'clock.</p><p class="mt-2"><b>2) Only / merely:</b></p><p><span class="fc font-bold text-lg">他才五岁。</span><br><span style="color:var(--muted)">Tā cái wǔ suì.</span><br>He is only five years old.</p>'},
  {lv:'HSK 3',t:'The 一边...一边 Structure',cn:'一边...一边',py:'yìbiān...yìbiān',f:'"While" — two simultaneous actions.',en:'I eat while listening to music.',b:'<p>一边 is repeated before each verb to indicate both actions happen at the same time.</p><p class="mt-2"><span class="fc font-bold text-lg">我一边吃饭一边听音乐。</span><br><span style="color:var(--muted)">Wǒ yìbiān chīfàn yìbiān tīng yīnyuè.</span><br>I listen to music while eating.</p><p><span class="fc font-bold text-lg">他一边走路一边看手机。</span><br><span style="color:var(--muted)">Tā yìbiān zǒulù yìbiān kàn shǒujī.</span><br>He looks at his phone while walking.</p>'},
  {lv:'HSK 3',t:'The 如果...就 Conditional',cn:'如果...就',py:'rúguǒ...jiù',f:'"If... then" — expressing a condition.',en:'If it rains, I won\'t go.',b:'<p><b>Structure:</b> 如果 + condition + 就 + result</p><p class="mt-2"><span class="fc font-bold text-lg">如果下雨，我就不去。</span><br><span style="color:var(--muted)">Rúguǒ xiàyǔ, wǒ jiù bú qù.</span><br>If it rains, I won\'t go.</p><p><span class="fc font-bold text-lg">如果有时间，我就去看电影。</span><br><span style="color:var(--muted)">Rúguǒ yǒu shíjiān, wǒ jiù qù kàn diànyǐng.</span><br>If I have time, I will go see a movie.</p>'},
  {lv:'HSK 4',t:'The 不仅...而且 Structure (Review)',cn:'不仅...而且',py:'bùjǐn...érqiě',f:'"Not only... but also" — adding emphasis.',en:'Not only does he speak Chinese, he also writes it.',b:'<p>A common paired conjunction used to emphasize that both statements are true.</p><p class="mt-2"><span class="fc font-bold text-lg">他不仅会说中文，而且会写汉字。</span><br><span style="color:var(--muted)">Tā bùjǐn huì shuō Zhōngwén, érqiě huì xiě Hànzì.</span><br>Not only can he speak Chinese, he can also write characters.</p><p><span class="fc font-bold text-lg">这家餐厅不仅价格便宜，而且味道很好。</span><br><span style="color:var(--muted)">Zhè jiā cāntīng bùjǐn jiàgé piányi, érqiě wèidào hěn hǎo.</span><br>This restaurant is not only cheap, but also tastes great.</p>'},
  {lv:'HSK 4',t:'The 各 Specifier',cn:'各',py:'gè',f:'"Each / every" — referring to all members individually.',en:'Each person has their own opinion.',b:'<p>各 is used before nouns or measure words to mean "each" or "every," emphasizing the individual members of a group.</p><p class="mt-2"><span class="fc font-bold text-lg">每个人都有自己的想法。</span><br><span style="color:var(--muted)">Měi gè rén dōu yǒu zìjǐ de xiǎngfǎ.</span><br>Each person has their own thoughts.</p><p><span class="fc font-bold text-lg">世界各国都有不同的文化。</span><br><span style="color:var(--muted)">Shìjiè gè guó dōu yǒu bùtóng de wénhuà.</span><br>Every country in the world has a different culture.</p>'},
  {lv:'HSK 4',t:'The 或者 Conjunction',cn:'或者',py:'huòzhě',f:'"Or" — presents alternatives (in statements).',en:'You can drink tea or coffee.',b:'<p>或者 is used in statements. 还是 is used in questions.</p><p class="mt-2"><span class="fc font-bold text-lg">你可以喝茶或者咖啡。</span><br><span style="color:var(--muted)">Nǐ kěyǐ hē chá huòzhě kāfēi.</span><br>You can drink tea or coffee.</p><p><span class="fc font-bold text-lg">我明天或者后天去。</span><br><span style="color:var(--muted)">Wǒ míngtiān huòzhě hòutiān qù.</span><br>I will go tomorrow or the day after.</p>'},
  {lv:'HSK 5',t:'The 此外 Conjunction',cn:'此外',py:'cǐwài',f:'"In addition / besides" — adding supplementary information.',en:'The price is reasonable. In addition, the location is great.',b:'<p>此外 is used in formal or written Chinese to add additional points, similar to "furthermore."</p><p class="mt-2"><span class="fc font-bold text-lg">价格合理。此外，位置也很好。</span><br><span style="color:var(--muted)">Jiàgé hélǐ. Cǐwài, wèizhì yě hěn hǎo.</span><br>The price is reasonable. In addition, the location is also great.</p><p><span class="fc font-bold text-lg">她擅长画画，此外还会弹钢琴。</span><br><span style="color:var(--muted)">Tā shàncháng huà huà, cǐwài hái huì tán gāngqín.</span><br>She excels at painting; in addition, she can play the piano.</p>'},
  {lv:'HSK 5',t:'The 不仅...还 Structure',cn:'不仅...还',py:'bùjǐn...hái',f:'"Not only... but also" — continuing with more.',en:'He not only runs fast, but also swims well.',b:'<p>Similar to 不仅...而且, but 还 is slightly more colloquial.</p><p class="mt-2"><span class="fc font-bold text-lg">他不仅跑得快，还游得很好。</span><br><span style="color:var(--muted)">Tā bùjǐn pǎo de kuài, hái yóu de hěn hǎo.</span><br>Not only does he run fast, he also swims well.</p><p><span class="fc font-bold text-lg">这种手机不仅功能强大，价格还不贵。</span><br><span style="color:var(--muted)">Zhè zhǒng shǒujī bùjǐn gōngnéng qiángdà, jiàgé hái bú guì.</span><br>This kind of phone is not only powerful but also not expensive.</p>'},
  {lv:'HSK 5',t:'The 由于...因此 Structure',cn:'由于...因此',py:'yóuyú...yīncǐ',f:'"Due to... therefore" — formal cause and effect.',en:'Due to the heavy rain, therefore the match was cancelled.',b:'<p>A formal cause-and-effect pattern. 由于 introduces the reason, and 因此 introduces the result.</p><p class="mt-2"><span class="fc font-bold text-lg">由于下大雨，因此比赛取消了。</span><br><span style="color:var(--muted)">Yóuyú xià dàyǔ, yīncǐ bǐsài qǔxiāo le.</span><br>Due to the heavy rain, the match was cancelled.</p><p><span class="fc font-bold text-lg">由于缺乏经验，因此他失败了。</span><br><span style="color:var(--muted)">Yóuyú quēfá jīngyàn, yīncǐ tā shībài le.</span><br>Due to lack of experience, he failed.</p>'},
  {lv:'HSK 6',t:'The 从而 Conjunction',cn:'从而',py:'cóng’ér',f:'"Thereby / thus" — indicating a resulting action.',en:'The company expanded, thereby creating jobs.',b:'<p>从而 introduces a result or consequence that follows logically. Used in formal writing.</p><p class="mt-2"><span class="fc font-bold text-lg">公司扩大了规模，从而创造了更多就业。</span><br><span style="color:var(--muted)">Gōngsī kuòdà le guīmó, cóng’ér chuàngzào le gèng duō jiùyè.</span><br>The company expanded, thereby creating more jobs.</p><p><span class="fc font-bold text-lg">他努力学习，从而考上了大学。</span><br><span style="color:var(--muted)">Tā nǔlì xuéxí, cóng’ér kǎoshàng le dàxué.</span><br>He studied hard, thereby getting into university.</p>'},
  {lv:'HSK 6',t:'The 如果...那么 Structure',cn:'如果...那么',py:'rúguǒ...nàme',f:'"If... then" — formal conditional.',en:'If this plan fails, then we need a backup.',b:'<p>A more formal version of 如果...就, often used in writing and speeches.</p><p class="mt-2"><span class="fc font-bold text-lg">如果这个计划失败，那么我们就要启动备用方案。</span><br><span style="color:var(--muted)">Rúguǒ zhège jìhuà shībài, nàme wǒmen jiù yào qǐdòng bèiyòng fāng’àn.</span><br>If this plan fails, then we will need to activate the backup plan.</p><p><span class="fc font-bold text-lg">如果大家都同意，那么我们就开始吧。</span><br><span style="color:var(--muted)">Rúguǒ dàjiā dōu tóngyì, nàme wǒmen jiù kāishǐ ba.</span><br>If everyone agrees, then let us begin.</p>'},
  {lv:'HSK 6',t:'The 正是 Emphasis',cn:'正是',py:'zhèng shì',f:'"It is precisely / exactly" — strong emphasis.',en:'This is precisely what I meant.',b:'<p>正是 emphasizes that something is exactly or precisely the case. Used in both speech and writing.</p><p class="mt-2"><span class="fc font-bold text-lg">这正是我的意思。</span><br><span style="color:var(--muted)">Zhè zhèng shì wǒ de yìsi.</span><br>This is precisely what I meant.</p><p><span class="fc font-bold text-lg">现在正是学习的好时候。</span><br><span style="color:var(--muted)">Xiànzài zhèng shì xuéxí de hǎo shíhou.</span><br>Now is exactly the right time to study.</p>'},
  {lv:'HSK 7',t:'The 但凡 Conjunction',cn:'但凡',py:'dàn fán',f:'"Whenever / if only" — general condition.',en:'Whenever I have time, I exercise.',b:'<p>但凡 is a formal conjunction meaning "if only / whenever" and introduces a condition that always holds true.</p><p class="mt-2"><span class="fc font-bold text-lg">但凡有时间，我就去锻炼。</span><br><span style="color:var(--muted)">Dànfán yǒu shíjiān, wǒ jiù qù duànliàn.</span><br>Whenever I have time, I go exercise.</p><p><span class="fc font-bold text-lg">但凡努力过的人，都不会后悔。</span><br><span style="color:var(--muted)">Dànfán nǔlì guò de rén, dōu bú huì hòuhuǐ.</span><br>Anyone who has worked hard will not regret it.</p>'},
  {lv:'HSK 7',t:'The 无非 Adverb',cn:'无非',py:'wú fēi',f:'"Nothing but / merely" — downplaying.',en:'It is nothing but a misunderstanding.',b:'<p>无非 reduces the importance or severity of something, meaning "nothing more than."</p><p class="mt-2"><span class="fc font-bold text-lg">这无非是一场误会。</span><br><span style="color:var(--muted)">Zhè wúfēi shì yì chǎng wùhuì.</span><br>This is nothing but a misunderstanding.</p><p><span class="fc font-bold text-lg">他无非是想帮你而已。</span><br><span style="color:var(--muted)">Tā wúfēi shì xiǎng bāng nǐ éryǐ.</span><br>He merely wants to help you.</p>'},
  {lv:'HSK 7',t:'The 一味 Adverb',cn:'一味',py:'yí wèi',f:'"Blindly / persistently" — often negative connotation.',en:'Blindly complaining will not solve the problem.',b:'<p>一味 describes doing something persistently or blindly, often with a negative implication.</p><p class="mt-2"><span class="fc font-bold text-lg">一味抱怨解决不了问题。</span><br><span style="color:var(--muted)">Yíwèi bàoyuàn jiějué bù liǎo wèntí.</span><br>Blindly complaining will not solve the problem.</p><p><span class="fc font-bold text-lg">不能一味追求速度而忽视质量。</span><br><span style="color:var(--muted)">Bùnéng yíwèi zhuīqiú sùdù ér hūshì zhìliàng.</span><br>One cannot blindly pursue speed while ignoring quality.</p>'},
  {lv:'HSK 8',t:'The 基于 Preposition (Advanced)',cn:'基于',py:'jī yú',f:'"Based on" — formal grounds.',en:'Based on the data, we propose a new method.',b:'<p>基于 is a formal preposition that introduces the basis or grounds for an action or conclusion.</p><p class="mt-2"><span class="fc font-bold text-lg">基于以上数据，我们提出了一种新方法。</span><br><span style="color:var(--muted)">Jīyú yǐshàng shùjù, wǒmen tíchū le yì zhǒng xīn fāngfǎ.</span><br>Based on the above data, we proposed a new method.</p><p><span class="fc font-bold text-lg">基于安全理由，活动取消了。</span><br><span style="color:var(--muted)">Jīyú ānquán lǐyóu, huódòng qǔxiāo le.</span><br>Based on safety reasons, the event was cancelled.</p>'},
  {lv:'HSK 8',t:'The 依旧 Adverb',cn:'依旧',py:'yī jiù',f:'"As before / still" — unchanged state.',en:'Ten years later, the city still looks the same.',b:'<p>依旧 indicates that a situation or state remains unchanged over time. More literary than 还是.</p><p class="mt-2"><span class="fc font-bold text-lg">十年过去了，这座城市依旧那么美。</span><br><span style="color:var(--muted)">Shí nián guòqù le, zhè zuò chéngshì yījiù nàme měi.</span><br>Ten years have passed, this city is still as beautiful.</p><p><span class="fc font-bold text-lg">他依旧坚持自己的理想。</span><br><span style="color:var(--muted)">Tā yījiù jiānchí zìjǐ de lǐxiǎng.</span><br>He still persists in his ideals.</p>'},
  {lv:'HSK 8',t:'The 日益 Adverb',cn:'日益',py:'rì yì',f:'"Increasingly / day by day" — gradual change.',en:'The situation is becoming increasingly complex.',b:'<p>日益 describes a gradual increase or change over time. Very common in formal and news Chinese.</p><p class="mt-2"><span class="fc font-bold text-lg">情况日益复杂。</span><br><span style="color:var(--muted)">Qíngkuàng rìyì fùzá.</span><br>The situation is becoming increasingly complex.</p><p><span class="fc font-bold text-lg">两国关系日益密切。</span><br><span style="color:var(--muted)">Liǎng guó guānxì rìyì mìqiè.</span><br>Bilateral relations are growing closer day by day.</p>'},
  {lv:'HSK 9',t:'The 鉴于 Preposition',cn:'鉴于',py:'jiàn yú',f:'"In view of / given" — formal premise.',en:'Given the current situation, we must act immediately.',b:'<p>鉴于 is used in formal writing to introduce a fact or consideration that forms the basis for a decision.</p><p class="mt-2"><span class="fc font-bold text-lg">鉴于目前的情况，我们得立即行动。</span><br><span style="color:var(--muted)">Jiànyú mùqián de qíngkuàng, wǒmen děi lìjí xíngdòng.</span><br>Given the current situation, we must act immediately.</p><p><span class="fc font-bold text-lg">鉴于他的优秀表现，公司决定提拔他。</span><br><span style="color:var(--muted)">Jiànyú tā de yōuxiù biǎoxiàn, gōngsī juédìng tíbá tā.</span><br>In view of his excellent performance, the company decided to promote him.</p>'},
  {lv:'HSK 9',t:'The 与...相比 Structure',cn:'与...相比',py:'yǔ...xiāng bǐ',f:'"Compared with/to" — formal comparison.',en:'Compared with last year, sales have increased.',b:'<p>与...相比 is a formal comparison structure used in writing and reports.</p><p class="mt-2"><span class="fc font-bold text-lg">与去年相比，销售额增长了百分之二十。</span><br><span style="color:var(--muted)">Yǔ qùnián xiāng bǐ, xiāoshòu’é zēngzhǎng le bǎi fēn zhī èrshí.</span><br>Compared with last year, sales increased by 20 percent.</p><p><span class="fc font-bold text-lg">与传统方法相比，新技术更加高效。</span><br><span style="color:var(--muted)">Yǔ chuántǒng fāngfǎ xiāng bǐ, xīn jìshù gèngjiā gāoxiào.</span><br>Compared with traditional methods, the new technology is more efficient.</p>'},
  {lv:'HSK 9',t:'The 换言之 Conjunction',cn:'换言之',py:'huàn yán zhī',f:'"In other words" — reformulating.',en:'The project is behind schedule. In other words, we need more time.',b:'<p>换言之 is a formal/literary way to rephrase or restate something for clarity. Equivalent to 换句话说 but more formal.</p><p class="mt-2"><span class="fc font-bold text-lg">项目进度落后了。换言之，我们需要更多时间。</span><br><span style="color:var(--muted)">Xiàngmù jìndù luòhòu le. Huànyánzhī, wǒmen xūyào gèng duō shíjiān.</span><br>The project is behind schedule. In other words, we need more time.</p><p><span class="fc font-bold text-lg">他没有通过考试。换言之，他得再考一次。</span><br><span style="color:var(--muted)">Tā méiyǒu tōngguò kǎoshì. Huànyánzhī, tā děi zài kǎo yí cì.</span><br>He did not pass the exam. In other words, he has to take it again.</p>'},
  {lv:'HSK 1',t:'The 是...的 Emphasis Structure',cn:'是...的',py:'shì...de',f:'"It is... that" — emphasizes time, place, or manner.',en:'It was yesterday that I arrived.',b:'<p>是...的 wraps around the emphasized element in a past action. Used to highlight how/when/where something happened.</p><p class="mt-2"><span class="fc font-bold text-lg">我是昨天到的。</span><br><span style="color:var(--muted)">Wǒ shì zuótiān dào de.</span><br>It was yesterday that I arrived.</p><p><span class="fc font-bold text-lg">他是从北京来的。</span><br><span style="color:var(--muted)">Tā shì cóng Běijīng lái de.</span><br>He came from Beijing.</p>'},
  {lv:'HSK 1',t:'The 有 Existence Verb',cn:'有',py:'yǒu',f:'"To have / there is" — indicates possession or existence.',en:'I have a book.',b:'<p>有 indicates possession (to have) or existence (there is/are). Negated with 没有.</p><p class="mt-2"><span class="fc font-bold text-lg">我有一本书。</span><br><span style="color:var(--muted)">Wǒ yǒu yì běn shū.</span><br>I have a book.</p><p><span class="fc font-bold text-lg">桌子上有一杯水。</span><br><span style="color:var(--muted)">Zhuōzi shàng yǒu yì bēi shuǐ.</span><br>There is a glass of water on the table.</p><p><span class="fc font-bold text-lg">我没有时间。</span><br><span style="color:var(--muted)">Wǒ méiyǒu shíjiān.</span><br>I don\'t have time.</p>'},
  {lv:'HSK 1',t:'The 在 Location Verb',cn:'在',py:'zài',f:'"At / in / on" — indicates location or existence in a place.',en:'I am at home.',b:'<p>在 can be a verb meaning "to be located at" or a preposition indicating location.</p><p class="mt-2"><span class="fc font-bold text-lg">我在家。</span><br><span style="color:var(--muted)">Wǒ zài jiā.</span><br>I am at home.</p><p><span class="fc font-bold text-lg">他在学校学习。</span><br><span style="color:var(--muted)">Tā zài xuéxiào xuéxí.</span><br>He studies at school.</p>'},
  {lv:'HSK 1',t:'The 不 Negative Adverb',cn:'不',py:'bù',f:'"Not" — negates verbs and adjectives.',en:'I don\'t like it.',b:'<p>不 is placed before the verb or adjective to negate it. 没/没有 negates past actions or possession.</p><p class="mt-2"><span class="fc font-bold text-lg">我不喜欢。</span><br><span style="color:var(--muted)">Wǒ bù xǐhuān.</span><br>I don\'t like it.</p><p><span class="fc font-bold text-lg">他不是老师。</span><br><span style="color:var(--muted)">Tā bú shì lǎoshī.</span><br>He is not a teacher.</p><p><span class="fc font-bold text-lg">我不去。</span><br><span style="color:var(--muted)">Wǒ bú qù.</span><br>I\'m not going.</p>'},
  {lv:'HSK 1',t:'The 了 Completion Particle',cn:'了',py:'le',f:'"Already / changed" — indicates completion or change of state.',en:'I ate.',b:'<p>了 has two main uses:</p><p><b>1) Verb + 了 (completion):</b></p><p><span class="fc font-bold text-lg">我吃了。</span><br><span style="color:var(--muted)">Wǒ chī le.</span><br>I ate.</p><p class="mt-2"><b>2) Sentence-final 了 (change of state):</b></p><p><span class="fc font-bold text-lg">下雨了。</span><br><span style="color:var(--muted)">Xiàyǔ le.</span><br>It\'s raining (now).</p>'},
  {lv:'HSK 2',t:'The 比 Comparison',cn:'比',py:'bǐ',f:'"Than" — comparative structure.',en:'She is taller than me.',b:'<p><b>Structure:</b> A + 比 + B + adjective</p><p>Used to compare two things. The adjective can be further modified with degree words.</p><p class="mt-2"><span class="fc font-bold text-lg">她比我高。</span><br><span style="color:var(--muted)">Tā bǐ wǒ gāo.</span><br>She is taller than me.</p><p><span class="fc font-bold text-lg">今天比昨天热。</span><br><span style="color:var(--muted)">Jīntiān bǐ zuótiān rè.</span><br>Today is hotter than yesterday.</p>'},
  {lv:'HSK 2',t:'The 能 Ability Verb',cn:'能',py:'néng',f:'"Can / be able to" — expresses ability or permission.',en:'I can swim.',b:'<p>能 expresses ability that is physically or objectively possible. 会 expresses learned skills.</p><p class="mt-2"><span class="fc font-bold text-lg">我能游泳。</span><br><span style="color:var(--muted)">Wǒ néng yóuyǒng.</span><br>I can swim.</p><p><span class="fc font-bold text-lg">这里不能停车。</span><br><span style="color:var(--muted)">Zhèlǐ bùnéng tíngchē.</span><br>You cannot park here.</p>'},
  {lv:'HSK 2',t:'The 吧 Suggestive Particle',cn:'吧',py:'ba',f:'"Let\'s / shall we" — suggestions, requests, or uncertainty.',en:'Let\'s go eat.',b:'<p>吧 softens commands into suggestions. Used with 我们 for "let\'s." Also shows uncertainty.</p><p class="mt-2"><span class="fc font-bold text-lg">我们吃饭吧。</span><br><span style="color:var(--muted)">Wǒmen chīfàn ba.</span><br>Let\'s eat.</p><p><span class="fc font-bold text-lg">快走吧。</span><br><span style="color:var(--muted)">Kuài zǒu ba.</span><br>Let\'s go quickly.</p>'},
  {lv:'HSK 3',t:'The 就 Adverb (Early)',cn:'就',py:'jiù',f:'"Then / right away" — indicates earliness or logical consequence.',en:'I will go right away.',b:'<p>就 has several meanings: 1) Earlier than expected; 2) Logical result (if... then); 3) Emphasis on immediacy.</p><p class="mt-2"><span class="fc font-bold text-lg">我马上就来。</span><br><span style="color:var(--muted)">Wǒ mǎshàng jiù lái.</span><br>I will come right away.</p><p><span class="fc font-bold text-lg">他七点就到了。</span><br><span style="color:var(--muted)">Tā qī diǎn jiù dào le.</span><br>He arrived as early as 7 o\'clock.</p>'},
  {lv:'HSK 3',t:'The 虽然...但是 Structure',cn:'虽然...但是',py:'suīrán...dànshì',f:'"Although... but" — concessive clause.',en:'Although it is expensive, it is worth it.',b:'<p><b>Structure:</b> 虽然 + concession + 但是/可是 + contrast</p><p>Although the first clause is true, the second clause presents a contrasting fact.</p><p class="mt-2"><span class="fc font-bold text-lg">虽然很贵，但是值得。</span><br><span style="color:var(--muted)">Suīrán hěn guì, dànshì zhídé.</span><br>Although it is expensive, it is worth it.</p><p><span class="fc font-bold text-lg">虽然下雨了，但是他还是去了。</span><br><span style="color:var(--muted)">Suīrán xiàyǔ le, dànshì tā háishì qù le.</span><br>Although it rained, he still went.</p>'},
  {lv:'HSK 3',t:'The 因为...所以 Structure',cn:'因为...所以',py:'yīnwèi...suǒyǐ',f:'"Because... therefore" — cause and effect.',en:'Because it was raining, I stayed home.',b:'<p><b>Structure:</b> 因为 + reason + 所以 + result</p><p>The most common way to express cause and effect. Either 因为 or 所以 can be omitted.</p><p class="mt-2"><span class="fc font-bold text-lg">因为下雨了，所以我在家。</span><br><span style="color:var(--muted)">Yīnwèi xiàyǔ le, suǒyǐ wǒ zài jiā.</span><br>Because it rained, I stayed home.</p><p><span class="fc font-bold text-lg">因为生病了，他没来上课。</span><br><span style="color:var(--muted)">Yīnwèi shēngbìng le, tā méi lái shàngkè.</span><br>Because he was sick, he didn\'t come to class.</p>'},
  {lv:'HSK 3',t:'The 先...然后 Sequence',cn:'先...然后',py:'xiān...ránhòu',f:'"First... then" — sequencing actions.',en:'First wash your hands, then eat.',b:'<p>先 introduces the first action, 然后 introduces the next action in sequence.</p><p class="mt-2"><span class="fc font-bold text-lg">先洗手，然后吃饭。</span><br><span style="color:var(--muted)">Xiān xǐshǒu, ránhòu chīfàn.</span><br>First wash your hands, then eat.</p><p><span class="fc font-bold text-lg">我先去银行，然后去超市。</span><br><span style="color:var(--muted)">Wǒ xiān qù yínháng, ránhòu qù chāoshì.</span><br>I\'ll go to the bank first, then to the supermarket.</p>'},
  {lv:'HSK 3',t:'The 或者 vs 还是 Conjunction',cn:'或者',py:'huòzhě',f:'"Or" — 或者 for statements, 还是 for questions.',en:'Do you want tea or coffee?',b:'<p>Use 或者 in statements and 还是 in questions to present alternatives.</p><p class="mt-2"><span class="fc font-bold text-lg">你想喝茶还是咖啡？</span><br><span style="color:var(--muted)">Nǐ xiǎng hē chá háishì kāfēi?</span><br>Do you want tea or coffee?</p><p><span class="fc font-bold text-lg">我们可以喝茶或者咖啡。</span><br><span style="color:var(--muted)">Wǒmen kěyǐ hē chá huòzhě kāfēi.</span><br>We can drink tea or coffee.</p>'},
  {lv:'HSK 4',t:'The 越...越 Structure',cn:'越...越',py:'yuè...yuè',f:'"The more... the more" — parallel increase.',en:'The more you practice, the better you get.',b:'<p><b>Structure:</b> 越 + verb/adjective + 越 + verb/adjective</p><p>Indicates that as one thing increases, another increases correspondingly.</p><p class="mt-2"><span class="fc font-bold text-lg">越练习越好。</span><br><span style="color:var(--muted)">Yuè liànxí yuè hǎo.</span><br>The more you practice, the better.</p><p><span class="fc font-bold text-lg">雨越下越大。</span><br><span style="color:var(--muted)">Yǔ yuè xià yuè dà.</span><br>The rain is getting heavier and heavier.</p>'},
  {lv:'HSK 4',t:'The 只要...就 Structure',cn:'只要...就',py:'zhǐyào...jiù',f:'"As long as" — sufficient condition.',en:'As long as you work hard, you will succeed.',b:'<p><b>Structure:</b> 只要 + condition + 就 + result</p><p>Expresses that one condition alone is sufficient to produce a result.</p><p class="mt-2"><span class="fc font-bold text-lg">只要努力，就能成功。</span><br><span style="color:var(--muted)">Zhǐyào nǔlì, jiù néng chénggōng.</span><br>As long as you work hard, you will succeed.</p><p><span class="fc font-bold text-lg">只要你有时间，我就陪你去。</span><br><span style="color:var(--muted)">Zhǐyào nǐ yǒu shíjiān, wǒ jiù péi nǐ qù.</span><br>As long as you have time, I will go with you.</p>'},
  {lv:'HSK 4',t:'The 只有...才 Structure',cn:'只有...才',py:'zhǐyǒu...cái',f:'"Only if" — necessary condition.',en:'Only if you practice every day will you improve.',b:'<p><b>Structure:</b> 只有 + necessary condition + 才 + result</p><p>Unlike 只要 (sufficient condition), 只有 emphasizes that this condition is absolutely necessary.</p><p class="mt-2"><span class="fc font-bold text-lg">只有每天练习，才会进步。</span><br><span style="color:var(--muted)">Zhǐyǒu měitiān liànxí, cái huì jìnbù.</span><br>Only by practicing every day will you improve.</p><p><span class="fc font-bold text-lg">只有你亲自去，才能了解情况。</span><br><span style="color:var(--muted)">Zhǐyǒu nǐ qīnzì qù, cáinéng liǎojiě qíngkuàng.</span><br>Only if you go yourself can you understand the situation.</p>'},
  {lv:'HSK 4',t:'The 即使...也 Structure',cn:'即使...也',py:'jíshǐ...yě',f:'"Even if" — concessive hypothetical.',en:'Even if it rains, I will still go.',b:'<p><b>Structure:</b> 即使 + hypothetical + 也 + result</p><p>States that the result holds true even under an unlikely or extreme condition.</p><p class="mt-2"><span class="fc font-bold text-lg">即使下雨，我也要去。</span><br><span style="color:var(--muted)">Jíshǐ xiàyǔ, wǒ yě yào qù.</span><br>Even if it rains, I will still go.</p><p><span class="fc font-bold text-lg">即使失败了，也不要放弃。</span><br><span style="color:var(--muted)">Jíshǐ shībài le, yě búyào fàngqì.</span><br>Even if you fail, don\'t give up.</p>'},
  {lv:'HSK 5',t:'The 尽管...还是 Structure',cn:'尽管...还是',py:'jìnguǎn...háishi',f:'"Despite... still" — conceding a strong contrast.',en:'Despite the difficulties, we still finished on time.',b:'<p><b>Structure:</b> 尽管 + fact + 还是 + result</p><p>Stronger than 虽然...但是. 尽管 acknowledges a real fact, yet the result remains unchanged.</p><p class="mt-2"><span class="fc font-bold text-lg">尽管困难重重，我们还是按时完成了。</span><br><span style="color:var(--muted)">Jìnguǎn kùnnán chóngchóng, wǒmen háishì ànshí wánchéng le.</span><br>Despite numerous difficulties, we still finished on time.</p><p><span class="fc font-bold text-lg">尽管他不愿意，他还是来了。</span><br><span style="color:var(--muted)">Jìnguǎn tā bú yuànyì, tā háishì lái le.</span><br>Despite his reluctance, he still came.</p>'},
  {lv:'HSK 5',t:'The 不但...而且 Structure',cn:'不但...而且',py:'búdàn...érqiě',f:'"Not only... but also" — escalating addition.',en:'He not only speaks Chinese well, but also writes beautifully.',b:'<p><b>Structure:</b> 不但 + A + 而且 + B (escalation)</p><p>B must be a stronger or additional point compared to A.</p><p class="mt-2"><span class="fc font-bold text-lg">他不但中文说得好，而且写得很漂亮。</span><br><span style="color:var(--muted)">Tā búdàn Zhōngwén shuō de hǎo, érqiě xiě de hěn piàoliang.</span><br>Not only does he speak Chinese well, but he also writes beautifully.</p><p><span class="fc font-bold text-lg">这种手机不但功能多，而且价格合理。</span><br><span style="color:var(--muted)">Zhè zhǒng shǒujī búdàn gōngnéng duō, érqiě jiàgé hélǐ.</span><br>This phone not only has many functions but also has a reasonable price.</p>'},
  {lv:'HSK 6',t:'The 纷纷 Adverb',cn:'纷纷',py:'fēnfēn',f:'"One after another / in succession" — describing simultaneous, uncoordinated actions.',en:'People expressed their opinions one after another.',b:'<p>纷纷 describes many people doing something at the same time but independently. Often used with 发表, 议论, 表示.</p><p class="mt-2"><span class="fc font-bold text-lg">大家纷纷发表意见。</span><br><span style="color:var(--muted)">Dàjiā fēnfēn fābiǎo yìjiàn.</span><br>Everyone expressed their opinions one after another.</p><p><span class="fc font-bold text-lg">人们纷纷捐款帮助灾区。</span><br><span style="color:var(--muted)">Rénmen fēnfēn juānkuǎn bāngzhù zāiqū.</span><br>People donated one after another to help the disaster area.</p>'},
  {lv:'HSK 6',t:'The 毕竟 Adverb',cn:'毕竟',py:'bìjìng',f:'"After all / in the end" — emphasizing a fundamental fact.',en:'After all, he is still a child.',b:'<p>毕竟 reasserts a fundamental or obvious fact that explains or concludes something. Similar to "after all."</p><p class="mt-2"><span class="fc font-bold text-lg">他毕竟还是个孩子。</span><br><span style="color:var(--muted)">Tā bìjìng háishì gè háizi.</span><br>After all, he is still a child.</p><p><span class="fc font-bold text-lg">毕竟我们认识很多年了，彼此很了解。</span><br><span style="color:var(--muted)">Bìjìng wǒmen rènshi hěn duō nián le, bǐcǐ hěn liǎojiě.</span><br>After all, we have known each other for many years and understand each other well.</p>'},
  {lv:'HSK 7',t:'The 于 Preposition',cn:'于',py:'yú',f:'"At / in / for / to" — versatile formal preposition.',en:'He was born in Beijing.',b:'<p>于 is a formal/literary preposition with many uses: location, time, comparison, and direction. Equivalent to 在, 对, 比, etc. in formal contexts.</p><p class="mt-2"><span class="fc font-bold text-lg">他出生于北京。</span><br><span style="color:var(--muted)">Tā chūshēng yú Běijīng.</span><br>He was born in Beijing.</p><p><span class="fc font-bold text-lg">这次比赛于下周一举行。</span><br><span style="color:var(--muted)">Zhè cì bǐsài yú xià zhōuyī jǔxíng.</span><br>The competition will be held next Monday.</p><p><span class="fc font-bold text-lg">学习在于坚持。</span><br><span style="color:var(--muted)">Xuéxí zàiyú jiānchí.</span><br>Learning lies in persistence.</p>'},
  {lv:'HSK 7',t:'The 及 Conjunction',cn:'及',py:'jí',f:'"And / as well as" — formal conjunctive.',en:'The company and its subsidiaries.',b:'<p>及 is a formal conjunction connecting nouns, similar to 和 but used in writing. Often appears in 以及 (as well as).</p><p class="mt-2"><span class="fc font-bold text-lg">公司及其子公司。</span><br><span style="color:var(--muted)">Gōngsī jí qí zǐgōngsī.</span><br>The company and its subsidiaries.</p><p><span class="fc font-bold text-lg">苹果、香蕉以及各种水果。</span><br><span style="color:var(--muted)">Píngguǒ, xiāngjiāo yǐjí gè zhǒng shuǐguǒ.</span><br>Apples, bananas, as well as various fruits.</p>'},
  {lv:'HSK 8',t:'The 诸 Pronoun',cn:'诸',py:'zhū',f:'"All / various" — literary plural marker.',en:'All the experts have expressed their opinions.',b:'<p>诸 means "all" or "various" and is used before nouns in formal writing. It is a literary equivalent of 各位 or 各种.</p><p class="mt-2"><span class="fc font-bold text-lg">诸位专家都发表了意见。</span><br><span style="color:var(--muted)">Zhū wèi zhuānjiā dōu fābiǎo le yìjiàn.</span><br>All the experts expressed their opinions.</p><p><span class="fc font-bold text-lg">诸多因素导致了这个结果。</span><br><span style="color:var(--muted)">Zhū duō yīnsù dǎozhì le zhège jiéguǒ.</span><br>Numerous factors led to this result.</p>'},
  {lv:'HSK 8',t:'The 自 Preposition',cn:'自',py:'zì',f:'"From / since" — formal origin marker.',en:'This custom dates from the Tang Dynasty.',b:'<p>自 is a formal/literary preposition indicating the starting point in time or space. Equivalent to 从 but more literary.</p><p class="mt-2"><span class="fc font-bold text-lg">这种习俗自唐代开始。</span><br><span style="color:var(--muted)">Zhè zhǒng xísú zì Tángdài kāishǐ.</span><br>This custom dates from the Tang Dynasty.</p><p><span class="fc font-bold text-lg">自即日起生效。</span><br><span style="color:var(--muted)">Zì jírì qǐ shēngxiào.</span><br>Effective from today.</p>'},
  {lv:'HSK 9',t:'The 予/予以 Verb Pattern',cn:'予以',py:'yǔ yǐ',f:'"To give / to grant" — formal verb used before two-syllable nouns.',en:'We will give this matter our full attention.',b:'<p>予以 is a formal verb used before abstract nouns (like 关注, 支持, 帮助) to express "give/provide." It is never used before a single object noun.</p><p class="mt-2"><span class="fc font-bold text-lg">我们将予以充分关注。</span><br><span style="color:var(--muted)">Wǒmen jiāng yǔ yǐ chōngfèn guānzhù.</span><br>We will give this matter full attention.</p><p><span class="fc font-bold text-lg">对每位申请者我们都予以认真考虑。</span><br><span style="color:var(--muted)">Duì měi wèi shēnqǐngzhě wǒmen dōu yǔ yǐ rènzhēn kǎolǜ.</span><br>We give each applicant careful consideration.</p>'},
  {lv:'HSK 9',t:'The 勿 Negative Adverb',cn:'勿',py:'wù',f:'"Do not" — formal/literary prohibition.',en:'Do not enter.',b:'<p>勿 is a formal negative imperative used in signs, notices, and literary writing. Stronger and more formal than 别 or 不要.</p><p class="mt-2"><span class="fc font-bold text-lg">请勿入内。</span><br><span style="color:var(--muted)">Qǐng wù rù nèi.</span><br>Please do not enter.</p><p><span class="fc font-bold text-lg">请勿吸烟。</span><br><span style="color:var(--muted)">Qǐng wù xīyān.</span><br>No smoking.</p><p><span class="fc font-bold text-lg">切勿模仿。</span><br><span style="color:var(--muted)">Qiè wù mófǎng.</span><br>Do not attempt to imitate.</p>'},
];

